svg.script:

const cellsContainer = document.getElementById('cells');
const linesContainer = document.getElementById('grid-lines');
const numpadContainer = document.getElementById('numpad');
const overlay = document.getElementById('overlay');
const helpOverlay = document.getElementById('help-overlay');
const menuOverlay = document.getElementById('menu-overlay');
const btnReset = document.getElementById('btn-reset');
const btnNew = document.getElementById('btn-new');
const btnHelp = document.getElementById('btn-help');

let solution = [];
let grid = [];
let initial = [];
let selectedCell = { r: -1, c: -1 };
let currentDifficulty = 'medium';

const baseGrid = [
    [5,3,4,6,7,8,9,1,2],
    [6,7,2,1,9,5,3,4,8],
    [1,9,8,3,4,2,5,6,7],
    [8,5,9,7,6,1,4,2,3],
    [4,2,6,8,5,3,7,9,1],
    [7,1,3,9,2,4,8,5,6],
    [9,6,1,5,3,7,2,8,4],
    [2,8,7,4,1,9,6,3,5],
    [3,4,5,2,8,6,1,7,9]
];

function shuffleGrid() {
    let g = JSON.parse(JSON.stringify(baseGrid));
    const swap = (arr, i, j) => { let t = arr[i]; arr[i] = arr[j]; arr[j] = t; };
    for(let i=0; i<3; i++) {
        let start = i*3;
        for(let j=0; j<3; j++) swap(g, start + Math.floor(Math.random()*3), start + Math.floor(Math.random()*3));
    }
    for(let i=0; i<3; i++) {
        let start = i*3;
        for(let j=0; j<3; j++) {
            let colA = start + Math.floor(Math.random()*3);
            let colB = start + Math.floor(Math.random()*3);
            for(let r=0; r<9; r++) {
                let t = g[r][colA]; g[r][colA] = g[r][colB]; g[r][colB] = t;
            }
        }
    }
    return g;
}

function initGame(diff) {
    currentDifficulty = diff;
    solution = shuffleGrid();
    grid = JSON.parse(JSON.stringify(solution));
    initial = Array(9).fill().map(() => Array(9).fill(false));

    let removeCount = 40;
    if(diff === 'easy') removeCount = 30;
    if(diff === 'hard') removeCount = 55;

    let removed = 0;
    while(removed < removeCount) {
        let r = Math.floor(Math.random()*9);
        let c = Math.floor(Math.random()*9);
        if(grid[r][c] !== 0) {
            grid[r][c] = 0;
            removed++;
        }
    }

    for(let r=0; r<9; r++) {
        for(let c=0; c<9; c++) {
            if(grid[r][c] !== 0) initial[r][c] = true;
        }
    }
    drawBoard();
}

function drawBoard() {
    cellsContainer.innerHTML = '';
    linesContainer.innerHTML = '';
    for(let i=0; i<=9; i++) {
        const weight = (i % 3 === 0) ? 3 : 1;
        const color = (i % 3 === 0) ? '#34495e' : '#bdc3c7';
        const vLine = document.createElementNS("http://www.w3.org/2000/svg", "line");
        vLine.setAttribute('x1', i * 40 + 40); vLine.setAttribute('y1', 0);
        vLine.setAttribute('x2', i * 40 + 40); vLine.setAttribute('y2', 400);
        vLine.setAttribute('stroke', color); vLine.setAttribute('stroke-width', weight);
        linesContainer.appendChild(vLine);

        const hLine = document.createElementNS("http://www.w3.org/2000/svg", "line");
        hLine.setAttribute('x1', 0); hLine.setAttribute('y1', i * 40 + 40);
        hLine.setAttribute('x2', 400); hLine.setAttribute('y2', i * 40 + 40);
        hLine.setAttribute('stroke', color); hLine.setAttribute('stroke-width', weight);
        linesContainer.appendChild(hLine);
    }
    for(let r=0; r<9; r++) {
        for(let c=0; c<9; c++) {
            const g = document.createElementNS("http://www.w3.org/2000/svg", "g");
            g.setAttribute('style', 'cursor:pointer');
            const rect = document.createElementNS("http://www.w3.org/2000/svg", "rect");
            rect.setAttribute('x', c * 40 + 40);
            rect.setAttribute('y', r * 40 + 40);
            rect.setAttribute('width', 40);
            rect.setAttribute('height', 40);
            rect.setAttribute('fill', 'transparent');
            rect.setAttribute('stroke', 'transparent');
            const text = document.createElementNS("http://www.w3.org/2000/svg", "text");
            text.setAttribute('x', c * 40 + 60);
            text.setAttribute('y', r * 40 + 67);
            text.setAttribute('text-anchor', 'middle');
            text.setAttribute('dominant-baseline', 'central');
            text.setAttribute('font-size', '20');
            text.setAttribute('font-weight', initial[r][c] ? 'bold' : 'normal');
            text.setAttribute('fill', initial[r][c] ? '#2c3e50' : '#3498db');
            text.textContent = grid[r][c] || '';
            g.appendChild(rect);
            g.appendChild(text);
            g.addEventListener('click', () => selectCell(r, c));
            cellsContainer.appendChild(g);
        }
    }
    updateSelection();
}

function selectCell(r, c) {
    selectedCell = { r, c };
    updateSelection();
}

function updateSelection() {
    const allRects = cellsContainer.querySelectorAll('rect');
    allRects.forEach((rect, i) => {
        const r = Math.floor(i/9);
        const c = i % 9;
        if(r === selectedCell.r && c === selectedCell.c) {
            rect.setAttribute('fill', '#e1f5fe');
            rect.setAttribute('stroke', '#3498db');
        } else {
            rect.setAttribute('fill', 'transparent');
            rect.setAttribute('stroke', 'transparent');
        }
    });
}

function setNumber(num) {
    if(selectedCell.r === -1) return;
    const {r, c} = selectedCell;
    if(initial[r][c]) return;
    grid[r][c] = num;
    drawBoard();
    selectedCell = { r, c };
    updateSelection();
    if (isBoardFull() && JSON.stringify(grid) === JSON.stringify(solution)) {
        overlay.setAttribute('visibility', 'visible');
    }
}

function isBoardFull() {
    for(let r=0; r<9; r++)
        for(let c=0; c<9; c++)
            if(grid[r][c] === 0) return false;
    return true;
}

function createNumpad() {
    numpadContainer.innerHTML = '';
    for(let i=1; i<=9; i++) {
        const g = document.createElementNS("http://www.w3.org/2000/svg", "g");
        g.setAttribute('style', 'cursor:pointer');
        const rect = document.createElementNS("http://www.w3.org/2000/svg", "rect");
        rect.setAttribute('x', (i-1) * 42);
        rect.setAttribute('y', 0);
        rect.setAttribute('width', 38);
        rect.setAttribute('height', 40);
        rect.setAttribute('rx', '5');
        rect.setAttribute('fill', '#34495e');
        const text = document.createElementNS("http://www.w3.org/2000/svg", "text");
        text.setAttribute('x', (i-1) * 42 + 19);
        text.setAttribute('y', 25);
        text.setAttribute('text-anchor', 'middle');
        text.setAttribute('dominant-baseline', 'central');
        text.setAttribute('fill', 'white');
        text.setAttribute('font-weight', 'bold');
        text.textContent = i;
        g.appendChild(rect);
        g.appendChild(text);
        g.addEventListener('click', () => setNumber(i));
        numpadContainer.appendChild(g);
    }
}

btnReset.addEventListener('click', () => {
    grid = JSON.parse(JSON.stringify(solution));
    for(let r=0; r<9; r++) {
        for(let c=0; c<9; c++) {
            if(!initial[r][c]) grid[r][c] = 0;
        }
    }
    drawBoard();
});

btnNew.addEventListener('click', () => {
    menuOverlay.setAttribute('visibility', 'visible');
    overlay.setAttribute('visibility', 'hidden');
    helpOverlay.setAttribute('visibility', 'hidden');
});

btnHelp.addEventListener('click', () => {
    helpOverlay.setAttribute('visibility', 'visible');
});

helpOverlay.addEventListener('click', () => {
    helpOverlay.setAttribute('visibility', 'hidden');
});

document.getElementById('btn-easy').addEventListener('click', () => {
    initGame('easy');
    menuOverlay.setAttribute('visibility', 'hidden');
});
document.getElementById('btn-medium').addEventListener('click', () => {
    initGame('medium');
    menuOverlay.setAttribute('visibility', 'hidden');
});
document.getElementById('btn-hard').addEventListener('click', () => {
    initGame('hard');
    menuOverlay.setAttribute('visibility', 'hidden');
});

overlay.addEventListener('click', () => {
    menuOverlay.setAttribute('visibility', 'visible');
    overlay.setAttribute('visibility', 'hidden');
});

createNumpad();
